//! Real subprocess dispatch shim for ~/cargo-cicd's `cargo cicd <noun>
//! <verb>` command surface, generated by `cargo-cicd-pack` from
//! `packs/cargo-cicd-pack/ontology.ttl`'s `cnv:Command` individuals.
//!
//! Closes the handler-gap dimension's concrete missing piece named by
//! `.specify/maturity.ttl`'s `cg_010` row (`mat:d2`, "L1 -- nothing callable,
//! catalog only, no `cargo-cicd` invocation") and by
//! `docs/packs/L5_VALIDATION_REPORT.md`'s cargo-cicd-pack section, using the
//! same generic `std::process::Command` dispatch-shim structure
//! `mcpp-pack`'s `src/mcpp_dispatch.rs.tmpl` already proved for `~/mcpp`
//! (read in full as the structural reference for this template). Every
//! function below is a real, callable, compilable entry point -- it is a
//! *generic* dispatcher (it shells out to the real `cargo-cicd` binary)
//! rather than a reimplementation of each command's behavior, so the
//! handler gap is not fully zero: `cargo-cicd`'s own behavior still lives
//! in its binary, not in ontology-specified logic or another pack's
//! generated code. But no hand-written Rust handler function is required
//! for any of the 51 per-command wrappers to exist or compile; they are
//! 100% ontology-driven.
//!
//! `Command::new("cargo-cicd")` invokes the real binary directly (confirmed
//! at `~/cargo-cicd/Cargo.toml`'s `[[bin]] name = "cargo-cicd"`), passing
//! `<noun> <verb>` with no leading `cicd` token. This reaches the identical
//! clap parse as `cargo cicd <noun> <verb>` would: `~/cargo-cicd/src/main.rs`'s
//! `strip_cargo_subcommand_token` only removes a leading `"cicd"` argv[1]
//! when cargo itself injected one (per cargo's external-subcommand
//! convention, `cargo <name>` invokes `cargo-<name> <name> ...`); a direct
//! invocation without that token already matches what the binary expects
//! after stripping.
//!
//! Deliberately excludes the deprecated `cc:doctor-bare` row (`cnv:verb ""`,
//! see `ontology.ttl`'s header note #1): that row is retained in
//! `src/cargo_cicd_catalog.rs` only for backward-compatible lookup, but
//! `cargo-cicd doctor ""` is not a real invocation -- generating a callable
//! wrapper for it would build a broken command, not a real one. This
//! template's own `rows` query adds `FILTER(?verb != "")` (a second,
//! independent SPARQL query from the catalog template's, not the same
//! query text reused) so the deprecated row never reaches this file, while
//! the catalog's own query is left untouched and still carries it.

use std::process::Command;

/// Build (but do not run) the `cargo-cicd <noun> <verb> [extra_args...]`
/// command. Exposed separately from `dispatch` so tests can assert on the
/// constructed `Command`'s program/args without spawning a real process
/// (see `cargo_cicd_dispatch_proof.rs`, same pack).
pub fn build_command(noun: &str, verb: &str, extra_args: &[String]) -> Command {
    let mut cmd = Command::new("cargo-cicd");
    cmd.arg(noun).arg(verb);
    cmd.args(extra_args);
    cmd
}

/// Run `cargo-cicd <noun> <verb> [extra_args...]` and return its captured
/// output. Generic across every command in the catalog -- ontology-driven,
/// not a hand-written per-command handler.
pub fn dispatch(
    noun: &str, verb: &str, extra_args: &[String],
) -> std::io::Result<std::process::Output> {
    build_command(noun, verb, extra_args).output()
}

/// `cargo-cicd certification show` -- generated wrapper, ontology-driven.
pub fn certification_show(extra_args: &[String]) -> std::io::Result<std::process::Output> {
    dispatch("certification", "show", extra_args)
}

/// `cargo-cicd claude_context show` -- generated wrapper, ontology-driven.
pub fn claude_context_show(extra_args: &[String]) -> std::io::Result<std::process::Output> {
    dispatch("claude_context", "show", extra_args)
}

